int main(int argc, char *argv[]) {
    printf("Total arguments received: %d\n", argc);

    // Loop through each argument. Notice how argv[0] contains the program identifier.
    for (int i = 0; i < argc; i++) {
        printf("Argument [%d]: %s\n", i, argv[i]);
    }

    // Demonstrate that argv[argc] is indeed NULL
    if (argv[argc] == NULL) {
        printf("Terminal safety check passed: argv[argc] is NULL.\n");
    }
    return 0;
}

codeExample2.code:
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(int argc, char *argv[]) {
    // Validate that we have exactly the required number of parameters: program, op, num1, num2
    if (argc != 4) {
        printf("Error: Invalid arguments supplied.\n");
        printf("Usage: %s <operator> <num1> <num2>\n", argv[0]);
        printf("Supported operators: add, sub\n");
        return 1;
    }

    char *operator = argv[1];
    char *endptr1, *endptr2;

    // Parse integers using strtol instead of atoi for safer range and invalid character checks
    long num1 = strtol(argv[2], &endptr1, 10);
    long num2 = strtol(argv[3], &endptr2, 10);

    // Validate that conversion succeeded cleanly without leftover characters
    if (*endptr1 != '\0' || *endptr2 != '\0') {
        printf("Error: Operands must be valid integers.\n");
        return 1;
    }

    if (strcmp(operator, "add") == 0) {
        printf("Result: %ld\n", num1 + num2);
    } else if (strcmp(operator, "sub") == 0) {
        printf("Result: %ld\n", num1 - num2);
    } else {
        printf("Error: Unknown operator '%s'. Use 'add' or 'sub'.\n", operator);
        return 1;
    }

    return 0;
}

