```c
#include <string.h>

int has_flag(int argc, char *argv[], const char *flag) {
    if (argv == NULL || flag == NULL) return 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], flag) == 0) {
            return 1; // Flag detected
        }
    }
    return 0; // Flag not present
}
```

questionsAndAnswers.question:
Identify and correct the memory-safety error in this snippet:
```c
int main(int argc, char *argv[]) {
    char *input = argv[1];
    if (strcmp(input, "--help") == 0) {
        printf("Help menu active\n");
    }
    return 0;
}
```

questionsAndAnswers.answer:
The critical bug lies in accessing `argv[1]` without verifying if `argc > 1` first. If this program is executed without any arguments, `argc` will be 1, making `argv[1]` a NULL pointer. Running `strcmp(input, ...)` with a NULL parameter causes an immediate segmentation fault on execution.

Here is the corrected and safe code:

```c
#include <stdio.h>
#include <string.h>

int main(int argc, char *argv[]) {
    if (argc > 1 && argv[1] != NULL) {
        char *input = argv[1];
        if (strcmp(input, "--help") == 0) {
            printf("Help menu active\n");
        }
    } else {
        printf("No flags provided.\n");
    }
    return 0;
}
```

`atoi` is intrinsically unsafe. It does not report parsing errors. If `argv[1]` contains an invalid numeric string like `'abc'`, `atoi` silently returns `0`, making it impossible to differentiate between a real input value of `0` and a parsing failure. It also lacks overflow protection. 

Here is the robust alternative using `strtol`:

```c
#include <stdio.h>
#include <stdlib.h>

int main(int argc, char *argv[]) {
    if (argc < 2) return 1;

    char *endptr;
    long value = strtol(argv[1], &endptr, 10);

    if (endptr == argv[1]) {
        printf("Error: No numeric characters parsed at all!\n");
        return 1;
    } else if (*endptr != '\0') {
        printf("Error: Partial string remnants left unparsed: %s\n", endptr);
        return 1;
    }

    printf("Parsed value cleanly: %ld\n", value);
    return 0;
}
```

Here is the code implementation:

```c
#include <stdio.h>
#include <stdlib.h>

int main(int argc, char *argv[]) {
    if (argc < 2) {
        printf("No parameters supplied\n");
        return 0;
    }

    double sum = 0.0;
    for (int i = 1; i < argc; i++) {
        char *endptr;
        double num = strtod(argv[i], &endptr);
        if (*endptr != '\0') {
            printf("Error: Parsing failed at input arg [%d] (%s)\n", i, argv[i]);
            return 1;
        }
        sum += num;
    }

    printf("Total sum of arguments: %.4f\n", sum);
    return 0;
}
```

Here is the parsed string key-value code:

```c
#include <stdio.h>
#include <string.h>

int main(int argc, char *argv[]) {
    if (argc < 2) {
        printf("Usage: %s key1=value1 key2=value2 ...\n", argv[0]);
        return 1;
    }

    for (int i = 1; i < argc; i++) {
        char *arg = argv[i];
        char *equals_sign = strchr(arg, '=');

        if (equals_sign != NULL && equals_sign != arg && *(equals_sign + 1) != '\0') {
            ptrdiff_t key_len = equals_sign - arg;
            printf("Argument [%d] -> Key: %.*s | Value: %s\n", 
                   i, (int)key_len, arg, equals_sign + 1);
        } else {
            printf("Argument [%d] -> Invalid format: '%s' (Use key=value)\n", i, arg);
        }
    }
    return 0;
}
```

